import { CreateDisplayTextRequest, FinalLedDisplayApiSdk } from 'final-led-display-api-sdk';

(async () => {
  const finalLedDisplayApiSdk = new FinalLedDisplayApiSdk({});


  const createDisplayTextRequest: CreateDisplayTextRequest = {	
    text: "text"
  };

  const data = await finalLedDisplayApiSdk.displayText.createDisplayText(createDisplayTextRequest);

  console.log(data);
})();

